namespace SpaceOS.Modules.Abstractions.Domain.Results;

/// <summary>
/// Represents a glass component that requires external ordering (not CNC-machined).
/// Generated by ManufacturingDerivationService for slots with ComponentType == "Glass".
/// </summary>
public sealed record GlassOrderItem(
    Guid SlotId,
    string SlotName,
    decimal Width,
    decimal Height,
    int Quantity,
    string OrderDescription);
